import itertools
class Solution:
    def minTravelTime(self, l, n, k, position, time):
        internal = list(range(1, n - 1))
        best = float('inf')
        for combo in itertools.combinations(internal, k):
            removed = set(combo)
            poscur = []
            tmcur = []
            carry = 0
            for i in range(n):
                if i in removed:
                    carry += time[i]
                else:
                    poscur.append(position[i])
                    tmcur.append(time[i] + carry)
                    carry = 0
            cost = sum((poscur[a + 1] - poscur[a]) * tmcur[a] for a in range(len(poscur) - 1))
            if cost < best:
                best = cost
        return best

