import sys
from functools import lru_cache
class Solution:
    def minTravelTime(self, l, n, k, position, time):
        sys.setrecursionlimit(100000)
        presum = [0] * (n + 1)
        for i in range(n):
            presum[i + 1] = presum[i] + time[i]
        INF = float('inf')
        def segtime(prev, cur):
            if cur == 0:
                return time[0]
            return presum[cur + 1] - presum[prev + 1]
        @lru_cache(maxsize=None)
        def rec(prev, cur, r):
            if cur == n - 1:
                return 0 if r == k else INF
            st = segtime(prev, cur)
            best = INF
            for nxt in range(cur + 1, n):
                nr = r + (nxt - cur - 1)
                if nr > k:
                    break
                cost = (position[nxt] - position[cur]) * st
                sub = rec(cur, nxt, nr)
                if sub < INF and cost + sub < best:
                    best = cost + sub
            return best
        ans = rec(-1, 0, 0)
        rec.cache_clear()
        return ans

