var minTravelTime = function(l, n, k, position, time) {
    const presum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) presum[i + 1] = presum[i] + time[i];
    const INF = Infinity;
    function segtime(prev, cur) {
        if (cur === 0) return time[0];
        return presum[cur + 1] - presum[prev + 1];
    }
    const memo = new Map();
    function rec(prev, cur, r) {
        if (cur === n - 1) return r === k ? 0 : INF;
        const key = prev * 10000 + cur * 100 + r;
        if (memo.has(key)) return memo.get(key);
        const st = segtime(prev, cur);
        let best = INF;
        for (let nxt = cur + 1; nxt < n; nxt++) {
            const nr = r + (nxt - cur - 1);
            if (nr > k) break;
            const cost = (position[nxt] - position[cur]) * st;
            const sub = rec(cur, nxt, nr);
            if (sub < INF && cost + sub < best) best = cost + sub;
        }
        memo.set(key, best);
        return best;
    }
    return rec(-1, 0, 0);
};
